namespace sv_9f1634ed9443482a8cc58264fffad643.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Creamy spinach curry with soft paneer cubes.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and herbs.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Fresh fish and vegetables wrapped in seasoned rice and nori.", 40),
            new(8, "Ramen", "Rich pork broth with noodles, egg, and chashu.", 120),
            new(9, "Tempura", "Lightly battered and fried shrimp and vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_9f1634ed9443482a8cc58264fffad643.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in GetSortedRecipes())
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // Guard against a cancelled/stale response.
            if (token.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Expected when cuisine changed or component disposed — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
            return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes,
        };
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

