namespace sv_9f1634ed9443482a8cc58264fffad643.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich spiced tomato sauce.", 50),
            new(5, "Palak Paneer", "Creamy spinach curry with soft paneer cubes.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and herbs.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Fresh fish and vegetables wrapped in seasoned rice and nori.", 40),
            new(8, "Ramen", "Rich pork broth with noodles, egg, and chashu.", 120),
            new(9, "Tempura", "Lightly battered and fried shrimp and vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

